#include <stdio.h>
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int si[n], pi[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &si[i], &pi[i]);
    }
    for (int i = 0; i < m; i++) {
        int ci, ki;
        scanf("%d %d", &ci, &ki);
        int di[ki];
        for (int j = 0; j < ki; j++) {
            scanf("%d", &di[j]);
        }
        long long minCost = 1e18;
        for (int j = 0; j < n; j++) {
            int found = 0;
            for (int k = 0; k < ki; k++) {
                if (di[k] == j + 1) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                long long cost = pi[j] + (long long)(si[j] - ci) * (si[j] - ci);
                minCost = (cost < minCost) ? cost : minCost;
            }
        }
        printf("%lld\n", minCost);
    }
    return 0;
}

