import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
        int[] si = new int[n];
        int[] pi = new int[n];
        for (int i = 0; i < n; i++) {
            si[i] = sc.nextInt();
            pi[i] = sc.nextInt();
        }
        for (int i = 0; i < m; i++) {
            int ci = sc.nextInt();
            int ki = sc.nextInt();
            int[] di = new int[ki];
            for (int j = 0; j < ki; j++) {
                di[j] = sc.nextInt();
            }
            long minCost = Long.MAX_VALUE;
            for (int j = 0; j < n; j++) {
                int found = 0;
                for (int k = 0; k < ki; k++) {
                    if (di[k] == j + 1) {
                        found = 1;
                        break;
                    }
                }
                if (found == 0) {
                    long cost = pi[j] + (long)(si[j] - ci) * (si[j] - ci);
                    minCost = Math.min(minCost, cost);
                }
            }
            System.out.println(minCost);
        }
    }
}

