    const [ci, ki] = readline().split(' ').map(Number);
    const di = readline().split(' ').map(Number).slice(1);
    let minCost = Infinity;
    for (let j = 0; j < n; j++) {
        let found = false;
        for (let k = 0; k < ki; k++) {
            if (di[k] === j + 1) {
                found = true;
                break;
